const scrollBtn=document.getElementById("scrollBtn");if(scrollBtn){const o=document.querySelector(".progress-ring__circle");let s=0;if(o){const t=o.r.baseVal.value;s=2*Math.PI*t,o.style.strokeDasharray=`${s}`,o.style.strokeDashoffset=`${s}`}function setProgress(t){if(o){const e=s-t/100*s;o.style.strokeDashoffset=e}}function updateScrollProgress(){const o=window.scrollY,s=document.documentElement.scrollHeight-window.innerHeight;if(o>300?(scrollBtn.style.display="block",scrollBtn.style.opacity="1"):(scrollBtn.style.opacity="0",setTimeout(()=>{window.scrollY<=300&&(scrollBtn.style.display="none")},300)),s>0){setProgress(o/s*100)}}window.addEventListener("scroll",updateScrollProgress),updateScrollProgress(),scrollBtn.addEventListener("click",()=>{window.scrollTo({top:0,behavior:"smooth"})})}